import re

def norm_doc(d: str) -> str:
    return re.sub(r"[^a-z0-9]", "", d.casefold())

def norm_name(n: str) -> str:
    return re.sub(r"\s+", " ", n.casefold().strip())

def block_key(rec):
    ap = norm_name(rec["name"]).split()[-1]
    return f"{ap}|{rec['region'].casefold()}"

